package ua.university.sms.service;import org.springframework.stereotype.Service;import ua.university.sms.exception.NotFoundException;import ua.university.sms.model.dto.EnrollmentDtos.*;import ua.university.sms.model.entity.*;import ua.university.sms.repository.*;import java.util.*;
@Service public class EnrollmentService{private final EnrollmentRepository repo;private final StudentRepository students;private final CourseRepository courses;public EnrollmentService(EnrollmentRepository r,StudentRepository s,CourseRepository c){repo=r;students=s;courses=c;}public Response create(Request d){if(repo.existsByStudentIdAndCourseId(d.studentId(),d.courseId()))throw new IllegalStateException("Student is already enrolled in this course");Enrollment e=new Enrollment();apply(e,d);return dto(repo.save(e));}public Response get(Long id){return dto(find(id));}public List<Response> list(){return repo.findAll().stream().map(this::dto).toList();}public Response update(Long id,Request d){Enrollment e=find(id);apply(e,d);return dto(repo.save(e));}public Response setPaid(Long id,PaymentRequest p){Enrollment e=find(id);e.setPaid(p.paid());return dto(repo.save(e));}public Response setGrade(Long id,GradeRequest g){Enrollment e=find(id);e.setGrade(g.grade());return dto(repo.save(e));}public void delete(Long id){repo.delete(find(id));}public Double averageByCourse(Long courseId){return repo.averageGpaByCourse(courseId);}public Double averageBySemester(String semester){return repo.averageGpaBySemester(semester);}private Enrollment find(Long id){return repo.findById(id).orElseThrow(()->new NotFoundException("Enrollment not found: "+id));}private void apply(Enrollment e,Request d){Student s=students.findById(d.studentId()).orElseThrow(()->new NotFoundException("Student not found: "+d.studentId()));Course c=courses.findById(d.courseId()).orElseThrow(()->new NotFoundException("Course not found: "+d.courseId()));e.setStudent(s);e.setCourse(c);e.setPaid(d.paid());e.setGrade(d.grade());}private Response dto(Enrollment e){return new Response(e.getId(),e.getStudent().getId(),e.getStudent().getFullName(),e.getCourse().getId(),e.getCourse().getTitle(),e.isPaid(),e.getGrade(),e.getEnrolledAt());}}
